    let result = '';
    let count = 0;
    for (let i = s.length - 1; i >= 0; i--) {
        if (s[i] !== '-') {
            if (count === k) {
                result = '-' + result;
                count = 0;
            }
            result = s[i].toUpperCase() + result;
            count++;
        }
    }
    return result;
}
